interface ProjectCardProps {
    date: string;
    title: string;
    description: string[];
    index: number;
    tags: string[];
    technologies: string[];
    liveDemoUrl: string;
    codeUrl: string;
}
const ProjectCard: React.FC<ProjectCardProps> = ({ date, title, description, index, tags, technologies, liveDemoUrl, codeUrl }) => {
    const cardRef = useRef<HTMLDivElement>(null);
    const [isVisible, setIsVisible] = useState(false);

    useEffect(() => {
        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    setIsVisible(true);
                    observer.unobserve(entry.target);
                }
            },
            {
                threshold: 0.1,
            }
        );

        const currentRef = cardRef.current;
        if (currentRef) {
            observer.observe(currentRef);
        }

        return () => {
            if (currentRef) {
                observer.unobserve(currentRef);
            }
        };
    }, []);

    return (
        <div
            ref={cardRef}
            className={`bg-white/50 dark:bg-gray-800/50 backdrop-blur-sm p-8 rounded-3xl border border-gray-200/80 dark:border-gray-700/80 shadow-lg shadow-gray-500/5 hover:shadow-xl hover:shadow-gray-500/10 flex flex-col transition-all duration-700 ease-out ${
                isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'
            }`}
            style={{ transitionDelay: `${index * 100}ms` }}
        >
            <div className="flex justify-between items-start mb-4">
                <div className="flex items-center justify-center w-14 h-14 bg-indigo-100 dark:bg-indigo-900/50 rounded-2xl">
                    <CodeIcon className="text-indigo-500 dark:text-indigo-400 w-7 h-7" />
                </div>
            </div>
            <p className="text-indigo-500 dark:text-indigo-400 font-semibold text-xs tracking-widest uppercase mb-2">{date}</p>
            <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">{title}</h3>
            <ul className="space-y-2 list-disc list-inside text-gray-600 dark:text-gray-400 mb-4">
                {description.map((item, i) => <li key={i}>{item}</li>)}
            </ul>
             <div className="flex flex-wrap gap-2 mb-4">
                {tags.map(tag => (
                    <span key={tag} className="bg-indigo-100 text-indigo-800 dark:bg-indigo-500/20 dark:text-indigo-300 text-xs font-semibold px-3 py-1 rounded-full">
                        {tag}
                    </span>
                ))}
            </div>
            <p className="text-sm text-gray-600 dark:text-gray-400 mb-6 flex-grow">
                <span className="font-semibold text-gray-700 dark:text-gray-300">Technologies Used:</span> {technologies.join(', ')}
