                          rel={isExternalLink(c.href) ? "noopener noreferrer" : ""}
                          className="bg-white/50 backdrop-blur-sm p-8 rounded-3xl border border-gray-200/80 shadow-lg shadow-gray-500/5 hover:shadow-xl hover:shadow-gray-500/10 transition-all flex flex-col items-center text-center">
