                            <p className="font-semibold mt-1">{c.value}</p>
                        </a>
                    ))}
                </div>
            </section>

            <footer className="text-center py-8 text-gray-500 text-sm">
                <p>&copy; {new Date().getFullYear()} KINDIKERI SRUJAN KUMAR REDDY</p>
                <p className="text-xs mt-1">Architected for clarity and performance</p>
            </footer>

            <button className="fixed bottom-6 right-6 w-14 h-14 bg-indigo-500 text-white rounded-full flex items-center justify-center shadow-lg hover:bg-indigo-600 transition-colors z-50">
                <MessageSquareIcon className="w-7 h-7" />
            </button>

        </div>
    );
};

