const SkillModal: React.FC<{ skill: SkillDetail | null; onClose: () => void; }> = ({ skill, onClose }) => {
    const [isVisible, setIsVisible] = useState(false);
    const modalRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleKeyDown = (event: KeyboardEvent) => {
            if (event.key === 'Escape') onClose();
        };
        document.addEventListener('keydown', handleKeyDown);

        if (skill) {
            document.body.style.overflow = 'hidden';
            setTimeout(() => setIsVisible(true), 10);
        } else {
            setIsVisible(false);
        }

        return () => {
            document.removeEventListener('keydown', handleKeyDown);
            document.body.style.overflow = 'auto';
        };
    }, [skill, onClose]);

    if (!skill) return null;

    const handleBackdropClick = (e: React.MouseEvent<HTMLDivElement>) => {
        if (modalRef.current && !modalRef.current.contains(e.target as Node)) {
            onClose();
        }
    };

    return (
        <div
            onClick={handleBackdropClick}
            className={`fixed inset-0 z-50 flex items-center justify-center p-4 transition-opacity duration-300 ${isVisible ? 'opacity-100' : 'opacity-0'}`}
            style={{ backgroundColor: 'rgba(0, 0, 0, 0.6)' }}
            aria-modal="true"
            role="dialog"
        >
            <div
                ref={modalRef}
                className={`bg-white rounded-3xl shadow-2xl w-full max-w-lg max-h-[90vh] overflow-y-auto p-8 md:p-10 transition-all duration-300 ease-out ${isVisible ? 'scale-100 opacity-100' : 'scale-95 opacity-0'}`}
            >
                <button onClick={onClose} className="absolute top-4 right-4 text-gray-400 hover:text-gray-800 transition-colors z-10" aria-label="Close skill details">
                    <XIcon className="w-8 h-8" />
                </button>
                <div className="flex items-center gap-4 mb-4">
                    <div className="flex-shrink-0 w-12 h-12 bg-indigo-100 rounded-xl flex items-center justify-center">
                        {skillIcons[skill.name] || <CodeIcon className="w-7 h-7 text-indigo-500" />}
                    </div>
                    <h2 className="text-3xl font-extrabold text-gray-900">{skill.name}</h2>
                </div>

                <div className="prose max-w-none text-gray-600">
                    <p className="lead">{skill.description}</p>
                    <h3 className="text-lg font-bold text-gray-800 mt-6 mb-2">Relevance in Data Science</h3>
                    <p>{skill.relevance}</p>
                </div>
            </div>
        </div>
    );
};


